func (r *sessionRepo) queryList(ctx context.Context, q string, args ...any) ([]Session, error) {
	rows, err := r.db.QueryContext(ctx, q, args...)
	if err != nil {
		return nil, fmt.Errorf("query sessions: %w", err)
	}
	defer func() { _ = rows.Close() }()

	var out []Session
	for rows.Next() {
		s, err := scanSession(rows)
		if err != nil {
			return nil, fmt.Errorf("scan session: %w", err)
		}
		out = append(out, s)
	}
	if err := rows.Err(); err != nil {
		return nil, fmt.Errorf("iterate sessions: %w", err)
	}
	return out, nil
}

// rowScanner unifies *sql.Row and *sql.Rows for scanSession.
type rowScanner interface {
	Scan(dest ...any) error
}

func scanSession(scanner rowScanner) (Session, error) {
	var (
		s             Session
		projectName   sql.NullString
		pid           sql.NullInt64
		metadata      sql.NullString
		createdAtUnix int64
		updatedAtUnix int64
	)
	err := scanner.Scan(
		&s.ID,
		&s.ProjectPath,
		&projectName,
		&s.AgentPlugin,
		&s.WorkspacePath,
		&s.ZellijSession,
		&pid,
		&metadata,
		&createdAtUnix,
		&updatedAtUnix,
	)
	if err != nil {
		return Session{}, err
	}

	if projectName.Valid {
		s.ProjectName = projectName.String
	}
	if pid.Valid {
		s.PID = pid.Int64
	}
	if metadata.Valid && metadata.String != "" {
		m := map[string]any{}
		if err := json.Unmarshal([]byte(metadata.String), &m); err != nil {
			return Session{}, fmt.Errorf("decode metadata: %w", err)
		}
		s.Metadata = m
	}
	s.CreatedAt = time.Unix(createdAtUnix, 0).UTC()
	s.UpdatedAt = time.Unix(updatedAtUnix, 0).UTC()

	return s, nil
}

